const raw = $input.first().json;
const execution = raw.execution || {};
const trigger = raw.trigger || {};
const workflow = raw.workflow || {};
const errorInfo = execution.error || trigger.error || {};

return [{
  json: {
    workflowId: workflow.id || '',
    workflowName: workflow.name || 'Unknown Workflow',
    executionId: execution.id || '',
    executionUrl: execution.url || '',
    lastNodeExecuted: execution.lastNodeExecuted || errorInfo?.node?.name || '',
    mode: execution.mode || trigger.mode || '',
    message: errorInfo.message || 'Workflow failed without a detailed message.',
    stack: errorInfo.stack || errorInfo.cause?.stack || '',
    timestamp: new Date().toISOString(),
    raw
  }
}];
